307→    borderWidth: 1,
308→    padding: spacing.md,
309→    gap: spacing.sm,
310→  },
311→  embeddedAuthorRow: {
312→    flexDirection: 'row',
313→    alignItems: 'center',
314→    gap: spacing.sm,
315→  },
316→  embeddedAuthorName: {
317→    fontSize: 13,
318→    fontFamily: fonts.ui.semiBold,
319→  },
320→  embeddedTitle: {
321→    ...typeScale.cardTitle,
322→    fontSize: 15,
