  1→import { apiRequest } from './apiClient';
  2→
  3→export type UserPreview = {
  4→  id: string;
  5→  name: string | null;
  6→  username?: string | null;
  7→  image_url?: string | null;
  8→  badge?: string | null;
  9→};
 10→
 11→export type JournalItem = {
 12→  id: string;
 13→  title: string | null;
 14→  content: string | null;
 15→  post_type?: string | null;
 16→  user_id?: string | null;
 17→  privacy?: string | null;
 18→  created_at?: string;
 19→  likes_count?: number;
 20→  comments_count?: number;
 21→  has_liked?: boolean;
 22→  has_bookmarked?: boolean;
 23→  user_reaction?: string | null;
 24→  reaction_count?: Array<{count?: number}>;
 25→  like_count?: Array<{count?: number}>;
 26→  comment_count?: Array<{count?: number}>;
 27→  bookmark_count?: Array<{count?: number}>;
 28→  is_repost?: boolean;
 29→  repost_caption?: string | null;
 30→  repost_source?: JournalItem | null;
 31→  users?: UserPreview | null;
 32→};
 33→
 34→export type CursorPage<T> = {
 35→  data: T[];
 36→  nextCursor?: string | null;
 37→  hasMore?: boolean;
 38→};
 39→
 40→export type NotificationItem = {
 41→  id: string;
 42→  sender_id?: string;
 43→  receiver_id?: string;
 44→  journal_id?: string;
 45→  repost_journal_id?: string | null;
 46→  opinion_id?: string | null;
 47→  type?: string;
 48→  source?: 'journal' | 'opinion' | string;
 49→  users?: UserPreview | null;
 50→  journals?: JournalItem | null;
 51→  opinions?: {
 52→    id?: string;
 53→    opinion?: string;
 54→    user_id?: string;
 55→    created_at?: string;
 56→  } | null;
 57→  message?: string;
 58→  created_at?: string;
 59→  read?: boolean;
 60→};
 61→
 62→type UniversePost = {
 63→  id: string;
 64→  title?: string | null;
 65→  x?: number;
 66→  y?: number;
 67→};
 68→
 69→export type StreakResponse = {
 70→  currentStreak?: number;
 71→  longestStreak?: number;
 72→  lastPostDate?: string | null;
 73→};
 74→
 75→type UserDataResponse = {
 76→  userData?: Array<{
 77→    id: string;
 78→    name?: string;
 79→    username?: string;
 80→    bio?: string;
 81→    image_url?: string;
 82→    badge_type?: string;
 83→    profile_layout?: any;
 84→    followers_count?: number;
 85→    following_count?: number;
 86→    posts_count?: number;
 87→    background?: Record<string, string> | null;
 88→    profile_font_color?: string | null;
 89→    dominant_colors?: string | null;
 90→    secondary_colors?: string | null;
 91→  }>;
 92→};
 93→
 94→const authHeaders = (token?: string): Record<string, string> => {
 95→  if (!token) {
 96→    return {};
 97→  }
 98→
 99→  return {
100→    Authorization: `Bearer ${token}`,
101→  };
102→};
103→
104→export const mobileApi = {
105→  async getJournals(cursor: string | null, limit = 10, userId?: string): Promise<CursorPage<JournalItem>> {
106→    const params = new URLSearchParams();
107→    params.set('limit', String(limit));
108→    if (cursor) {
109→      params.set('before', cursor);
110→    }
111→    if (userId) {
112→      params.set('userId', userId);
113→    }
114→
115→    return apiRequest<CursorPage<JournalItem>>(`/journals?${params.toString()}`, {
116→      method: 'GET',
117→    });
118→  },
119→
120→  async getJournalById(journalId: string, userId?: string): Promise<{ journal: JournalItem }> {
121→    const params = new URLSearchParams();
122→    if (userId) {
123→      params.set('userId', userId);
124→    }
125→
126→    const suffix = params.toString() ? `?${params.toString()}` : '';
127→    return apiRequest<{ journal: JournalItem }>(`/journal/${encodeURIComponent(journalId)}${suffix}`, {
128→      method: 'GET',
129→    });
130→  },
131→
132→  async searchUsers(query: string, limit = 20): Promise<{ data: UserPreview[]; hasMore: boolean }> {
133→    const params = new URLSearchParams();
134→    params.set('query', query.trim());
135→    params.set('limit', String(limit));
136→
137→    return apiRequest<{ data: UserPreview[]; hasMore: boolean }>(`/users/search?${params.toString()}`, {
138→      method: 'GET',
139→    });
140→  },
141→
142→  async searchJournals(query: string, limit = 20, userId?: string): Promise<{ data: JournalItem[]; hasMore: boolean }> {
143→    const params = new URLSearchParams();
144→    params.set('query', query.trim());
145→    params.set('limit', String(limit));
146→    if (userId) {
147→      params.set('userId', userId);
148→    }
149→
150→    return apiRequest<{ data: JournalItem[]; hasMore: boolean }>(`/journals/search?${params.toString()}`, {
151→      method: 'GET',
152→    });
153→  },
154→
155→  async getNotifications(token: string, cursor: string | null, limit = 20): Promise<CursorPage<NotificationItem>> {
156→    const params = new URLSearchParams();
157→    params.set('limit', String(limit));
158→    if (cursor) {
159→      params.set('before', cursor);
160→    }
161→
162→    return apiRequest<CursorPage<NotificationItem>>(`/getNotifications?${params.toString()}`, {
163→      method: 'GET',
164→      headers: {
165→        ...authHeaders(token),
166→      },
167→    });
168→  },
169→
170→  async getStreak(userId: string): Promise<StreakResponse> {
171→    return apiRequest<StreakResponse>(`/streak/${encodeURIComponent(userId)}`, {
172→      method: 'GET',
173→    });
174→  },
175→
176→  async getUserData(userId: string): Promise<UserDataResponse> {
177→    const params = new URLSearchParams();
178→    params.set('userId', userId);
179→
180→    return apiRequest<UserDataResponse>(`/getUserData?${params.toString()}`, {
181→      method: 'GET',
182→    });
183→  },
184→
185→  async getCanvasGallery(
186→    userId?: string,
187→    limit = 36,
188→    sort: 'hottest' | 'newest' = 'hottest',
189→    cursor?: string | null,
190→  ): Promise<CursorPage<JournalItem>> {
191→    const params = new URLSearchParams();
192→    params.set('limit', String(limit));
193→    params.set('sort', sort);
194→    if (userId) {
195→      params.set('userId', userId);
196→    }
197→    if (cursor) {
198→      params.set('cursor', cursor);
199→    }
200→
201→    return apiRequest<CursorPage<JournalItem>>(`/journals/canvas/gallery?${params.toString()}`, {
202→      method: 'GET',
203→    });
204→  },
205→
206→  async getUniversePosts(
207→    viewport: { minX: number; maxX: number; minY: number; maxY: number },
208→    limit = 200,
209→  ): Promise<{ data?: UniversePost[] }> {
210→    const params = new URLSearchParams();
211→    params.set('minX', String(viewport.minX));
212→    params.set('maxX', String(viewport.maxX));
213→    params.set('minY', String(viewport.minY));
214→    params.set('maxY', String(viewport.maxY));
215→    params.set('limit', String(limit));
216→
217→    return apiRequest<{ data?: UniversePost[] }>(`/universe/posts?${params.toString()}`, {
218→      method: 'GET',
219→    });
220→  },
221→
222→  async getUserByUsername(username: string): Promise<UserDataResponse> {
223→    return apiRequest<UserDataResponse>(
224→      `/user/${encodeURIComponent(username)}`,
225→      {method: 'GET'},
226→    );
227→  },
228→
229→  async getRelatedPosts(journalId: string): Promise<{data: JournalItem[]}> {
230→    return apiRequest<{data: JournalItem[]}>(
231→      `/journal/${encodeURIComponent(journalId)}/related`,
232→      {method: 'GET'},
233→    );
234→  },
235→
236→  async getUserJournals(token: string, userId: string, cursor: string | null, limit = 10): Promise<CursorPage<JournalItem>> {
237→    const params = new URLSearchParams();
238→    params.set('limit', String(limit));
239→    params.set('userId', userId);
240→    if (cursor) params.set('before', cursor);
241→    return apiRequest<CursorPage<JournalItem>>(`/userJournals?${params.toString()}`, {
242→      method: 'GET',
243→      headers: {Authorization: `Bearer ${token}`},
244→    });
245→  },
246→
247→  async saveJournal(token: string, payload: { title: string; plainText: string; html?: string }): Promise<{ message?: string }> {
248→    const formData = new FormData();
249→
250→    const lexicalPayload = {
251→      root: {
252→        children: [
253→          {
254→            type: 'paragraph',
255→            children: [
256→              {
257→                type: 'text',
258→                text: payload.plainText,
259→                detail: 0,
260→                format: 0,
261→                mode: 'normal',
262→                style: '',
263→                version: 1,
264→              },
265→            ],
266→            direction: null,
267→            format: '',
268→            indent: 0,
269→            version: 1,
270→          },
271→        ],
272→        direction: null,
273→        format: '',
274→        indent: 0,
275→        type: 'root',
276→        version: 1,
277→      },
278→    };
279→
280→    formData.append('title', payload.title);
281→    formData.append('content', JSON.stringify(lexicalPayload));
282→    formData.append('post_type', 'text');
283→
284→    return apiRequest<{ message?: string }>('/save-journal', {
285→      method: 'POST',
286→      headers: {
287→        ...authHeaders(token),
288→      },
289→      body: formData,
290→      timeoutMs: 30000,
291→      retries: 0,
292→    });
293→  },
294→};
