  1→import React, {useMemo, useState} from 'react';
  2→import {FlatList, ScrollView, StyleSheet, Text, View} from 'react-native';
  3→import {useInfiniteQuery, useMutation} from '@tanstack/react-query';
  4→import {NativeStackScreenProps} from '@react-navigation/native-stack';
  5→import {SafeAreaView} from 'react-native-safe-area-context';
  6→import {PostCard} from '../../components/PostCard/PostCard';
  7→import {PostCardSkeleton} from '../../components/SkeletonLoader';
  8→import {CommentModal} from '../../components/Comments';
  9→import {RepostModal} from '../../components/RepostModal';
 10→import {Chip} from '../../components/Chip';
 11→import {EmptyState} from '../../components/EmptyState';
 12→import {useAuth} from '../../features/auth/AuthProvider';
 13→import {useTheme} from '../../theme/ThemeProvider';
 14→import {fonts} from '../../theme/typography';
 15→import {spacing} from '../../theme/spacing';
 16→import {
 17→  mobileApi,
 18→  type CursorPage,
 19→  type JournalItem,
 20→} from '../../lib/api/mobileApi';
 21→import {socialApi} from '../../lib/api/socialApi';
 22→import {queryClient} from '../../lib/queryClient';
 23→import {useBookmarkMutation} from '../../hooks/useSocialMutations';
 24→import {
 25→  extractPlainText,
 26→  extractBannerImage,
 27→  resolveCount,
 28→  getNextCursor,
 29→} from '../../lib/utils/journalHelpers';
 30→import type {RootStackParamList} from '../../navigation/types';
 31→
 32→type Props = NativeStackScreenProps<RootStackParamList, 'Canvas'>;
 33→
 34→const PAGE_SIZE = 10;
 35→
 36→const SORT_OPTIONS = [
 37→  {key: 'hottest', label: 'Hottest'},
 38→  {key: 'newest', label: 'Newest'},
 39→] as const;
 40→
 41→type SortKey = (typeof SORT_OPTIONS)[number]['key'];
 42→
 43→export function CanvasScreen({navigation}: Props) {
 44→  const {user, session} = useAuth();
 45→  const {colors} = useTheme();
 46→  const token = session?.access_token ?? '';
 47→  const [refreshing, setRefreshing] = useState(false);
 48→  const [sort, setSort] = useState<SortKey>('hottest');
 49→  const [commentModal, setCommentModal] = useState<{
 50→    postId: string;
 51→    receiverId?: string;
 52→    commentCount: number;
 53→  } | null>(null);
 54→  const [repostModal, setRepostModal] = useState<{
 55→    journalId: string;
 56→    title?: string;
 57→    authorName?: string;
 58→    authorAvatar?: string;
 59→  } | null>(null);
 60→
 61→  const galleryQuery = useInfiniteQuery({
 62→    queryKey: ['canvas-gallery', user?.id, sort],
 63→    queryFn: ({pageParam}) =>
 64→      mobileApi.getCanvasGallery(user?.id, PAGE_SIZE, sort, pageParam ?? null),
 65→    initialPageParam: null as string | null,
 66→    getNextPageParam: lastPage => getNextCursor(lastPage, PAGE_SIZE),
 67→  });
 68→
 69→  const reactionMutation = useMutation({
 70→    mutationFn: async ({
 71→      journalId,
 72→      receiverId,
 73→      reactionType,
 74→    }: {
 75→      journalId: string;
 76→      receiverId: string;
 77→      reactionType: string;
 78→    }) => {
 79→      if (!token) throw new Error('Please log in to react.');
 80→      return socialApi.toggleReaction(token, {journalId, receiverId, reactionType});
 81→    },
 82→    onMutate: async ({journalId, reactionType}) => {
 83→      const qk = ['canvas-gallery', user?.id, sort];
 84→      await queryClient.cancelQueries({queryKey: qk});
 85→      const prev = queryClient.getQueryData<{pages: CursorPage<JournalItem>[]}>(qk);
 86→      if (prev) {
 87→        queryClient.setQueryData<{pages: CursorPage<JournalItem>[]}>(qk, old => {
 88→          if (!old) return old;
 89→          return {
 90→            ...old,
 91→            pages: old.pages.map(page => ({
 92→              ...page,
 93→              data: page.data.map(item => {
 94→                if (item.id !== journalId) return item;
 95→                const removing = item.user_reaction === reactionType;
 96→                const currentCount =
 97→                  (item.reaction_count?.[0]?.count ??
 98→                    item.like_count?.[0]?.count ??
 99→                    item.likes_count ??
100→                    0) as number;
101→                const delta = removing ? -1 : item.user_reaction ? 0 : 1;
102→                return {
103→                  ...item,
104→                  user_reaction: removing ? null : reactionType,
105→                  has_liked: removing ? false : true,
106→                  like_count: [{count: Math.max(0, currentCount + delta)}],
107→                };
108→              }),
109→            })),
110→          };
111→        });
112→      }
113→      return {prev};
114→    },
115→    onError: (_err, _vars, context) => {
116→      if (context?.prev) {
117→        queryClient.setQueryData(
118→          ['canvas-gallery', user?.id, sort],
119→          context.prev,
120→        );
121→      }
122→    },
123→    onSettled: () => {
124→      queryClient.invalidateQueries({queryKey: ['canvas-gallery']});
125→    },
126→  });
127→
128→  const bookmarkMutation = useBookmarkMutation(token, [
129→    'canvas-gallery',
130→    user?.id,
131→    sort,
132→  ]);
133→
134→  const handleReact = (
135→    journalId: string,
