  1→import { useEffect, useMemo, useState } from "react";
  2→import { Image as KonvaImage, Layer, Line, Rect, Stage, Text } from "react-konva";
  3→
  4→const FONT_BRUSHES = {
  5→    serif: {fontFamily: "\"Courier New\", \"Lucida Console\", monospace", fontStyle: "normal"},
  6→    handwritten: {fontFamily: "\"Comic Sans MS\", \"Bradley Hand\", cursive", fontStyle: "normal"},
  7→    bold: {fontFamily: "\"Trebuchet MS\", \"Gill Sans\", sans-serif", fontStyle: "bold"},
  8→    serifDisplay: {fontFamily: "Georgia, \"Times New Roman\", serif", fontStyle: "normal"}
  9→};
 10→
 11→const FONT_STYLE_MAP = {
 12→    serif: "serif",
 13→    handwritten: "handwritten",
 14→    bold: "bold",
 15→    mono: "serif",
 16→    serifDisplay: "serifDisplay"
 17→};
 18→
 19→const GRID_SIZE = 24;
 20→const OBJECT_LIFT_MULTIPLIER = 1.03;
 21→const DEFAULT_DOODLE_COLOR = "#ff2d55";
 22→
 23→const clamp = (value, min, max) => Math.min(Math.max(value, min), max);
 24→
 25→const getSnippetMetrics = (snippet, stageWidth) => {
 26→    const sizeScale = Number.isFinite(snippet?.sizeScale) ? snippet.sizeScale : 1;
 27→    const styleKey = FONT_STYLE_MAP[snippet?.fontStyle] || "serif";
 28→    const baseFontSize = styleKey === "bold" ? 34 : styleKey === "handwritten" ? 32 : 30;
 29→    const fontSize = clamp(baseFontSize * sizeScale, 18, 92);
 30→    const estimatedWidth = Math.max(120, Math.min(stageWidth * 0.78, Math.round(((snippet?.text?.length || 1) * fontSize) * 0.58)));
 31→    const charsPerLine = Math.max(8, Math.floor(estimatedWidth / (fontSize * 0.56)));
 32→    const lineCount = Math.max(1, Math.ceil((snippet?.text?.length || 1) / charsPerLine));
 33→    const height = Math.max(68, Math.round(lineCount * fontSize * 1.14 + 18));
 34→
 35→    return {width: estimatedWidth, height, fontSize};
 36→};
 37→
 38→const useLoadedImage = (src) => {
 39→    const [image, setImage] = useState(null);
 40→
 41→    useEffect(() => {
 42→        if(!src){
 43→            setImage(null);
 44→            return;
 45→        }
 46→
 47→        const img = new window.Image();
 48→        img.crossOrigin = "anonymous";
 49→        img.onload = () => setImage(img);
 50→        img.onerror = () => setImage(null);
 51→        img.src = src;
 52→
 53→        return () => {
 54→            img.onload = null;
 55→            img.onerror = null;
 56→        };
 57→    }, [src]);
 58→
 59→    return image;
 60→};
 61→
 62→const CanvasImageNode = ({
 63→    canvasImage,
 64→    stageWidth,
 65→    stageHeight,
 66→    isSelected,
 67→    isDragging,
 68→    onSelect,
 69→    onDragStart,
 70→    onDragEnd,
 71→    canInteract,
 72→    preventTouchDefault,
 73→    isBeingRemoved
 74→}) => {
 75→    const loadedImage = useLoadedImage(canvasImage?.src);
 76→    const objectWidth = clamp((canvasImage?.width || 0.3) * stageWidth, 56, stageWidth * 0.95);
 77→    const objectHeight = clamp((canvasImage?.height || 0.3) * stageHeight, 56, stageHeight * 0.95);
 78→    const x = clamp((canvasImage?.x || 0) * stageWidth, 0, Math.max(0, stageWidth - objectWidth));
 79→    const y = clamp((canvasImage?.y || 0) * stageHeight, 0, Math.max(0, stageHeight - objectHeight));
 80→    const liftMultiplier = isDragging ? OBJECT_LIFT_MULTIPLIER + 0.02 : isSelected ? OBJECT_LIFT_MULTIPLIER : 1;
 81→    const baseScaleX = canvasImage?.scaleX === -1 ? -1 : 1;
 82→
 83→    return (
 84→        <>
 85→            <KonvaImage
 86→                name={canvasImage?.id}
 87→                x={x}
 88→                y={y}
 89→                width={objectWidth}
 90→                height={objectHeight}
 91→                image={loadedImage}
 92→                draggable={canInteract && !isBeingRemoved}
 93→                rotation={canvasImage?.rotation || 0}
 94→                scaleX={baseScaleX * liftMultiplier}
 95→                scaleY={liftMultiplier}
 96→                shadowColor="rgba(0,0,0,0.3)"
 97→                shadowBlur={isSelected || isDragging ? 16 : 8}
 98→                shadowOffsetY={isSelected || isDragging ? 6 : 3}
 99→                preventDefault={preventTouchDefault}
100→                onClick={canInteract ? onSelect : undefined}
101→                onTap={canInteract ? onSelect : undefined}
102→                onDragStart={onDragStart}
103→                onDragEnd={onDragEnd}
104→            />
105→            {isSelected && (
106→                <Rect
107→                    x={x}
108→                    y={y}
109→                    width={objectWidth}
110→                    height={objectHeight}
111→                    stroke="#68d391"
112→                    strokeWidth={1.7}
113→                    dash={[6, 4]}
114→                    rotation={canvasImage?.rotation || 0}
115→                    listening={false}
116→                />
117→            )}
118→        </>
119→    );
120→};
121→
122→export const getCanvasStageHeight = (width, aspectRatio) => (aspectRatio === "4:5" ? Math.round(width * 1.25) : width);
123→
124→export const buildSortedCanvasObjects = (snippets = [], images = []) => {
125→    const snippetObjects = snippets.map((snippet) => ({kind: "snippet", payload: snippet}));
126→    const imageObjects = images.map((image) => ({kind: "image", payload: image}));
127→    return [...snippetObjects, ...imageObjects].sort((a, b) => (a?.payload?.zIndex || 0) - (b?.payload?.zIndex || 0));
128→};
