```typescript
export const parseCanvasDoc = (raw: unknown): CanvasDoc | null => {
  if (!raw) return null;
  try {
    return (typeof raw === 'string' ? JSON.parse(raw) : raw) as CanvasDoc;
  } catch {
    return null;
  }
};

export const getCanvasPlainText = (raw: unknown): string => {
  const doc = parseCanvasDoc(raw);
  if (!doc?.snippets?.length) return '';
  return doc.snippets
    .map(s => (typeof s?.text === 'string' ? s.text.trim() : ''))
    .filter(Boolean)
    .join(' ')
    .replace(/\s+/g, ' ')
    .trim();
};
```

